  ABUSE_CNT INT NOT NULL DEFAULT 0,
  PRIMARY KEY (DATE_STAT)
);
CREATE TABLE b_sender_file
(
	`ID`  INT UNSIGNED  auto_increment primary key,
	`FILE_ID`  INT UNSIGNED NOT NULL,
