    on b_sender_file (`FILE_ID`);
CREATE INDEX IX_SENDER_GROUP_CONNECTOR on b_sender_group_connector(GROUP_ID);
CREATE INDEX `IX_SENDER_MESSAGE_UTM_CODE` on `b_sender_message_utm` (`CODE`);
